import{c as i,Q as s,j as a,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Architecture and Runtime","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":1780240924000}'),o={name:"architecture.md"};function d(n,e,l,c,r,p){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="architecture-and-runtime" tabindex="-1">Architecture and Runtime <a class="header-anchor" href="#architecture-and-runtime" aria-label="Permalink to &quot;Architecture and Runtime&quot;">​</a></h1><p>This page maps the backend, frontend, runtime dependencies, and logging behavior.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The backend package lives in <code>src/dj_track_similarity/</code>.</p><ul><li><code>cli.py</code> exposes the <code>dj-sim</code> Typer CLI.</li><li><code>api.py</code> creates the FastAPI app; route groups live in <code>api_routes_*</code> modules.</li><li><code>database.py</code> is the public <code>LibraryDatabase</code> facade. Database internals are split into <code>db_tracks.py</code> for track CRUD, paging, likes, and relocation, <code>db_analysis.py</code> for embeddings, analysis writes, resets, and analyzer candidate selection, and <code>db_summary.py</code> for summary counters.</li><li><code>db_schema.py</code> defines the current SQLite schema and validation.</li><li><code>scanner.py</code> scans folders and reads Mutagen metadata.</li><li><code>scan_jobs.py</code>, <code>analysis_jobs.py</code>, <code>classifier_jobs.py</code>, and <code>tags.py</code> manage cancellable jobs and status objects.</li><li><code>audio_loader.py</code> provides shared native-first audio loading.</li><li><code>sonara_features.py</code> extracts the focused Sonara playlist feature set.</li><li><code>sonara_similarity.py</code> and <code>sonara_similarity_scoring.py</code> rank Sonara feature similarity.</li><li><code>embedding.py</code> contains MERT and CLAP embedding adapters.</li><li><code>genres.py</code> contains the MAEST genre adapter.</li><li><code>classifier_scoring.py</code> loads promoted classifier artifacts and scores feature-complete tracks.</li><li><code>tags.py</code> writes MAEST labels into the standard genre field and runs the cancellable genre-tag job; <code>wave_tags.py</code> provides the guarded WAV/ID3 genre-write path.</li><li><code>search.py</code> performs embedding-space similarity search.</li><li><code>exporter.py</code> writes M3U and CSV outputs.</li><li><code>runtime.py</code> selects <code>auto</code>, <code>cpu</code>, or <code>cuda</code> for PyTorch work.</li><li><code>dependencies.py</code> checks runtime dependencies such as <code>ffmpeg</code>.</li><li><code>logging_config.py</code> configures rotating file logs.</li></ul><p>The frontend lives in <code>frontend/src/</code>.</p><ul><li><code>api.ts</code> mirrors the FastAPI contract.</li><li><code>App.tsx</code> coordinates app state and workflows.</li><li><code>LibraryPanel.tsx</code> contains scan, refresh, analysis, reset, and clear controls.</li><li><code>TrackPanel.tsx</code>, <code>TrackRows.tsx</code>, and <code>TrackMetadataDialog.tsx</code> show library rows, liked-track controls, and track details.</li><li><code>SearchPlaylistPanel.tsx</code> contains SONARA, MERT, CLAP, and CLASS tabs plus export controls.</li></ul><h2 id="runtime-dependencies" tabindex="-1">Runtime Dependencies <a class="header-anchor" href="#runtime-dependencies" aria-label="Permalink to &quot;Runtime Dependencies&quot;">​</a></h2><p>Core runtime dependencies are declared in <code>pyproject.toml</code>:</p><ul><li><code>numpy&gt;=1.26,&lt;2.0</code></li><li><code>mutagen</code></li><li><code>pydantic</code></li><li><code>typer</code></li><li><code>fastapi</code></li><li><code>uvicorn</code></li><li><code>joblib</code></li></ul><p>Optional groups:</p><ul><li><code>sonara</code>: installs Sonara support.</li><li><code>ml</code>: installs the synchronized PyTorch/Torchaudio/Torchvision/TorchCodec stack, Transformers, Hugging Face Hub, LAION-CLAP, and MAEST support.</li><li><code>rhythm-lab</code>: installs scikit-learn for local classifier training and benchmarking in Rhythm Lab.</li><li><code>dev</code>: installs pytest and Ruff.</li></ul><p><code>ffmpeg</code> is required for robust server startup and audio decoding. It can be found from <code>PATH</code> or configured with:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DJ_TRACK_SIMILARITY_FFMPEG</span></span></code></pre></div><p>The verified Windows CUDA stack is:</p><ul><li>PyTorch <code>2.11.0</code></li><li>Torchaudio <code>2.11.0</code></li><li>Torchvision <code>0.26.0</code></li><li>TorchCodec <code>0.13.0</code></li><li>NumPy <code>&gt;=1.26,&lt;2.0</code></li><li>PyTorch wheel index <code>https://download.pytorch.org/whl/cu130</code></li></ul><p>Install the matching CUDA wheels from the official PyTorch wheel index before installing the remaining ML dependencies:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchvision</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.26</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchaudio</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torchcodec</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Use <code>.[sonara,ml,rhythm-lab,dev]</code> instead when the same environment will also train Rhythm Lab classifier profiles.</p><p>On Windows, TorchCodec-backed Torchaudio decoding needs an FFmpeg shared build with DLLs available on <code>PATH</code>, not only a static <code>ffmpeg.exe</code>. The portable tools setup should use GyanD <code>ffmpeg 8.1.1-full_build-shared</code> or a compatible <code>full_build-shared</code> FFmpeg layout such as:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\ffmpeg.exe</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avcodec-*.dll</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avformat-*.dll</span></span></code></pre></div><h2 id="logging" tabindex="-1">Logging <a class="header-anchor" href="#logging" aria-label="Permalink to &quot;Logging&quot;">​</a></h2><p>Runtime file logging defaults to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dj-track-similarity.log</span></span></code></pre></div><p>The log rotates daily at midnight and keeps one rotated day. INFO-level startup, completion, warning, and error summaries are written by default. Successful per-track job events are aggregated out of the file log unless detailed logging is enabled.</p><p>Environment variables:</p><ul><li><code>DJ_TRACK_SIMILARITY_LOG</code>: file log path.</li><li><code>DJ_TRACK_SIMILARITY_LOG_LEVEL</code>: <code>debug</code>, <code>info</code>, <code>warning</code>, <code>error</code>, or <code>critical</code>.</li><li><code>DJ_TRACK_SIMILARITY_LOG_TRACK_EVENTS</code>: set to <code>1</code>, <code>true</code>, <code>yes</code>, or <code>on</code> to write successful per-track job events.</li></ul><p>The server also exposes <code>--log-level</code> and <code>--log-track-events</code>.</p><p>The web UI keeps the top notice area for the latest short status message. A theme toggle beside it switches between light and dark UI palettes and stores the preference in browser storage. The log button next to the theme toggle opens a larger in-app log frame with the current process status and recent UI, scan, analysis, and genre-writing events.</p><p>CLI analysis commands print a live one-line progress display while they run. The line is redrawn in place and includes a progress bar, percentage, <code>processed/total</code>, track-level <code>analyzed</code> and <code>failed</code>, approximate <code>tracks/s</code>, and an estimated remaining time. This is console-only progress for the CLI process that started the job; it does not attach to jobs started by the web UI/server process.</p><p>CLI analysis commands can also write diagnostic timing lines to the file log when <code>--diagnostics</code> is passed on the command or <code>DJ_TRACK_SIMILARITY_ANALYSIS_DIAGNOSTICS=1</code> is set. These include batch-level model timing, <code>tracks_per_second</code>, track count, and window count where the selected adapter exposes those details. Audio loading also logs decoder fallback details by path: failed decoders such as <code>torchaudio</code>, <code>wave</code>, or <code>ffmpeg</code>, their error text, and the fallback decoder that eventually succeeded when one does. This diagnostic logging is off by default.</p>`,31)])])}const g=i(o,[["render",d]]);export{k as __pageData,g as default};
